import { useState, useEffect, useCallback, useRef } from "react";

// Preload Auth page module so navigating to /auth is instant (no Suspense flash)
const _preloadAuth = import("./Auth");
import { useTranslation } from "react-i18next";
import { Link, useSearchParams, useNavigate } from "react-router-dom";
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "@/hooks/use-toast";
import { useAuth } from "@/contexts/AuthContext";
import { useProfile } from "@/hooks/useProfile";
import { STORE_TYPES, type StoreType } from "@/lib/storeTypes";
import { cn } from "@/lib/utils";
import { Progress } from "@/components/ui/progress";
import {
  CheckCircle2, Loader2, Store, Phone, Mail, Check,
  ChevronRight, ChevronLeft, User, MapPin, Sparkles, Navigation, RefreshCw,
  AlertTriangle, Search, ArrowRight, Star, Heart, Clock, Camera, Upload, BookOpen
} from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { CardFooter } from "@/components/ui/card";
import { useSiteSettings } from "@/hooks/useSiteSettings";
import { getBuildingStoryParts } from "@/components/BuildingStorySection";

type AccountMode = "current" | "other" | "new";

interface FormState {
  storeType: StoreType;
  storeTypeCustom: string;
  accountMode: AccountMode | null;
  name: string;
  email: string;
  phone: string;
  storeName: string;
  storeAddress: string;
  isOwnStore: boolean | null;
  aiGeneratedData: any | null;
  autoPublishToCommunity: boolean;
}

const TOTAL_STEPS = 5;
const SESSION_STORAGE_KEY = "joinUs_formState";

const JoinUs = () => {
  const { t, i18n } = useTranslation();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const { data: profile } = useProfile();
  const { settings } = useSiteSettings();

  const [currentStep, setCurrentStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [isGeneratingPreview, setIsGeneratingPreview] = useState(false);
  const [locatingNearby, setLocatingNearby] = useState(false);
  const [nearbyPlaces, setNearbyPlaces] = useState<any[]>([]);
  const [showNearbyDialog, setShowNearbyDialog] = useState(false);
  const [isUploadingCover, setIsUploadingCover] = useState(false);
  const [draftStory, setDraftStory] = useState<{ zh: string; en: string; pt: string } | null>(null);
  
  const coverInputRef = useRef<HTMLInputElement>(null);

  const [form, setForm] = useState<FormState>({
    storeType: "restaurant",
    storeTypeCustom: "",
    accountMode: null,
    name: "",
    email: "",
    phone: "",
    storeName: "",
    storeAddress: "",
    isOwnStore: false,
    aiGeneratedData: null,
    autoPublishToCommunity: true,
  });

  // Restore state from sessionStorage if returning from auth or detail page
  useEffect(() => {
    const resumeJoinUs = searchParams.get("resumeJoinUs");
    const resumeFromDetail = searchParams.get("fromDetail");
    if (resumeJoinUs === "true" || resumeFromDetail === "true") {
      try {
        const savedState = sessionStorage.getItem(SESSION_STORAGE_KEY);
        if (savedState) {
          const parsed = JSON.parse(savedState);
          const savedStep = parsed._savedStep || 3;
          const savedDraftStory = parsed._savedDraftStory || null;
          delete parsed._savedStep;
          delete parsed._savedDraftStory;
          if (resumeFromDetail === "true") {
            // Returning from detail page - restore exact state
            setForm(prev => ({ ...prev, ...parsed }));
            setCurrentStep(savedStep);
            if (savedDraftStory) setDraftStory(savedDraftStory);
          } else {
            // Returning from auth
            const newAccountMode = parsed.accountMode === "new" ? "current" : "other";
            setForm(prev => ({ ...prev, ...parsed, accountMode: newAccountMode }));
            setCurrentStep(3);
          }
          sessionStorage.removeItem(SESSION_STORAGE_KEY);
          // Clean up URL
          window.history.replaceState({}, "", "/join-us");
        }
      } catch (e) {
        console.error("Failed to restore join us state:", e);
      }
    }
  }, [searchParams]);

  // Pre-fill user info when accountMode is "current"
  useEffect(() => {
    if (form.accountMode === "current" && profile && user) {
      setForm(prev => ({
        ...prev,
        name: prev.name || profile.display_name || "",
        email: prev.email || user.email || "",
        phone: prev.phone || profile.phone || "",
      }));
    }
  }, [form.accountMode, profile, user]);

  // Auto-fetch story when draft exists but story not loaded
  useEffect(() => {
    const draftId = form.aiGeneratedData?.draft_restaurant_id;
    if (draftId && !draftStory) {
      supabase
        .from("restaurants")
        .select("photo_story_zh, photo_story_en, photo_story_pt")
        .eq("id", draftId)
        .single()
        .then(({ data }) => {
          if (data && (data.photo_story_zh || data.photo_story_en || data.photo_story_pt)) {
            setDraftStory({
              zh: data.photo_story_zh || "",
              en: data.photo_story_en || "",
              pt: data.photo_story_pt || "",
            });
          }
        });
    }
  }, [form.aiGeneratedData?.draft_restaurant_id, draftStory]);

  const updateForm = (updates: Partial<FormState>) => {
    setForm(prev => ({ ...prev, ...updates }));
  };

  const handleCoverUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const allowedTypes = ["image/jpeg", "image/png", "image/webp"];
    if (!allowedTypes.includes(file.type)) {
      toast({ title: t("joinUs.coverUploadInvalidType", "仅支持 JPG、PNG、WebP 格式"), variant: "destructive" });
      return;
    }
    if (file.size > 5 * 1024 * 1024) {
      toast({ title: t("joinUs.coverUploadTooLarge", "图片不能超过 5MB"), variant: "destructive" });
      return;
    }
    const img = new Image();
    const objectUrl = URL.createObjectURL(file);
    img.src = objectUrl;
    await new Promise((resolve) => { img.onload = resolve; });
    URL.revokeObjectURL(objectUrl);
    if (img.width < 400 || img.height < 300) {
      toast({ title: t("joinUs.coverUploadTooSmall", "图片最小尺寸为 400×300 像素"), variant: "destructive" });
      return;
    }
    setIsUploadingCover(true);
    try {
      const ext = file.name.split(".").pop() || "jpg";
      const fileName = `join-requests/${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
      const { error: uploadError } = await supabase.storage
        .from("restaurant-images")
        .upload(fileName, file, { contentType: file.type, upsert: false });
      if (uploadError) throw uploadError;
      const { data: urlData } = supabase.storage.from("restaurant-images").getPublicUrl(fileName);
      updateForm({
        aiGeneratedData: {
          ...form.aiGeneratedData,
          cover_image_url: urlData.publicUrl,
          cover_image_source: "user_upload",
        },
      });
      toast({ title: t("joinUs.coverUploadSuccess", "封面上传成功，提交后将由管理员审核") });
    } catch (err: any) {
      console.error("Cover upload failed:", err);
      toast({ title: t("joinUs.coverUploadFailed", "上传失败，请重试"), variant: "destructive" });
    } finally {
      setIsUploadingCover(false);
      if (coverInputRef.current) coverInputRef.current.value = "";
    }
  };

  const validateStep = (): string | null => {
    switch (currentStep) {
      case 1:
        if (form.storeType === "other" && !form.storeTypeCustom.trim()) {
          return t("joinUs.storeTypeCustomRequired");
        }
        return null;
      case 2:
        if (!form.accountMode) return t("joinUs.selectAccountMode");
        if (form.accountMode === "current" && user) {
          if (!profile?.display_name) return t("joinUs.missingProfileInfo");
          if (!user.email) return t("joinUs.missingProfileInfo");
          if (!profile?.phone) return t("joinUs.missingProfileInfo");
        }
        return null;
      case 3:
        if (form.storeName.length < 2) return t("joinUs.restaurantNameMin");
        if (form.storeAddress.length < 2) return t("joinUs.addressMin");
        if (form.isOwnStore === null) return t("joinUs.selectOwnership", "请选择您与该商店的关系");
        return null;
      default:
        return null;
    }
  };

  const handleNext = () => {
    const error = validateStep();
    if (error) {
      toast({ title: error, variant: "destructive" });
      return;
    }
    if (currentStep === 4 && !form.aiGeneratedData) {
      generatePreview();
    }
    setCurrentStep(prev => Math.min(prev + 1, TOTAL_STEPS));
  };

  const handlePrev = () => setCurrentStep(prev => Math.max(prev - 1, 1));

  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  const handleSwitchAccount = () => {
    if (user) {
      setShowLogoutConfirm(true);
    } else {
      sessionStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(form));
      navigate("/auth?redirect=/join-us&resumeJoinUs=true");
    }
  };

  const confirmSwitchAccount = async () => {
    setShowLogoutConfirm(false);
    const redirectUrl = "/auth?redirect=/join-us&resumeJoinUs=true";
    sessionStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(form));
    // Store redirect target before signout, since signout triggers auth state change
    sessionStorage.setItem("joinUs_postLogoutRedirect", redirectUrl);
    await supabase.auth.signOut();
    // Navigate immediately after signout - use replace to prevent back-button issues
    window.location.href = redirectUrl;
  };

  // Generate AI preview
  const generatePreview = useCallback(async () => {
    setIsGeneratingPreview(true);
    try {
      const { data, error } = await supabase.functions.invoke("generate-store-preview", {
        body: {
          store_name: form.storeName,
          store_address: form.storeAddress,
          store_type: form.storeType === "other" ? form.storeTypeCustom : form.storeType,
          language: i18n.language,
        },
      });
      if (error) throw error;
      updateForm({ aiGeneratedData: data });
    } catch (e) {
      console.error("AI preview generation failed:", e);
      toast({ title: t("joinUs.aiPreviewError"), variant: "destructive" });
    } finally {
      setIsGeneratingPreview(false);
    }
  }, [form.storeName, form.storeAddress, form.storeType, form.storeTypeCustom, i18n.language, t]);

  // Auto-generate on entering step 4
  useEffect(() => {
    if (currentStep === 4 && !form.aiGeneratedData && !isGeneratingPreview) {
      generatePreview();
    }
  }, [currentStep]);

  // Nearby places search
  const searchNearbyPlaces = async () => {
    if (!navigator.geolocation) {
      toast({ title: "您的浏览器不支持定位功能", variant: "destructive" });
      return;
    }
    setLocatingNearby(true);
    try {
      const position = await new Promise<GeolocationPosition>((resolve, reject) => {
        console.log("Requesting geolocation...");
        navigator.geolocation.getCurrentPosition(
          (pos) => {
            console.log("Geolocation success:", pos.coords.latitude, pos.coords.longitude);
            resolve(pos);
          },
          (err) => {
            console.error("Geolocation error:", err.code, err.message);
            reject(err);
          },
          { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 }
        );
      });
      const { longitude, latitude } = position.coords;
      const token = import.meta.env.VITE_MAPBOX_TOKEN;
      if (!token) {
        toast({ title: "地图服务未配置", variant: "destructive" });
        return;
      }
      const typeQuery = form.storeType === "restaurant" || form.storeType === "ghost" 
        ? "restaurant" : form.storeType === "cafe" ? "cafe" : "shop";
      
      const res = await fetch(
        `https://api.mapbox.com/geocoding/v5/mapbox.places/${encodeURIComponent(typeQuery)}.json?proximity=${longitude},${latitude}&types=poi&limit=10&access_token=${token}`
      );
      const data = await res.json();
      console.log("Mapbox response:", data);
      if (data.features && data.features.length > 0) {
        const places = data.features.map((f: any) => ({
          name: f.text,
          address: f.place_name,
          distance: f.properties?.distance || 0,
          center: f.center,
        }));
        places.sort((a: any, b: any) => a.distance - b.distance);
        setNearbyPlaces(places);
        setShowNearbyDialog(true);
      } else {
        toast({ title: "附近没有找到相关店铺", variant: "destructive" });
      }
    } catch (e: any) {
      console.error("Location error:", e);
      if (e?.code === 1) {
        toast({ title: "定位权限被拒绝，请在浏览器设置中允许定位", variant: "destructive" });
      } else if (e?.code === 2) {
        toast({ title: "无法获取位置信息，请检查网络", variant: "destructive" });
      } else if (e?.code === 3) {
        toast({ title: "定位超时，请重试", variant: "destructive" });
      } else {
        toast({ title: t("restaurants.locationError"), variant: "destructive" });
      }
    } finally {
      setLocatingNearby(false);
    }
  };

  const onSubmit = async () => {
    setIsSubmitting(true);
    try {
      const currentLanguage = i18n.language || "en";
      const finalName = profile?.display_name || "";
      const finalEmail = user?.email || "";
      const finalPhone = profile?.phone || "";

      const { error } = await supabase.functions.invoke("send-join-request-email", {
        body: {
          name: finalName,
          email: finalEmail,
          phone: finalPhone,
          restaurant_name: form.storeName,
          restaurant_address: form.storeAddress,
          features_selected: ["decide_later"],
          language: currentLanguage,
          merchant_type: "shallow",
          store_type: form.storeType,
          store_type_custom: form.storeType === "other" ? form.storeTypeCustom : null,
          existing_user_id: user?.id || null,
          account_mode: form.accountMode,
          is_own_store: form.isOwnStore,
          ai_generated_data: form.aiGeneratedData,
        },
      });

      if (error) {
        if (error.message?.includes("rate_limit_exceeded")) {
          toast({ title: t("joinUs.rateLimitError"), description: t("joinUs.rateLimitErrorDesc"), variant: "destructive" });
        } else {
          throw error;
        }
        return;
      }

      setIsSuccess(true);
      toast({ title: t("joinUs.successTitle"), description: t("joinUs.successDescription") });
    } catch (error: any) {
      console.error("Error submitting join request:", error);
      toast({ title: t("common.error"), description: t("joinUs.submitError"), variant: "destructive" });
    } finally {
      setIsSubmitting(false);
    }
  };

  const contactPhone = settings?.join_contact_phone || "968815050";
  const contactEmail = settings?.contact_email;
  const progressPercent = (currentStep / TOTAL_STEPS) * 100;

  if (isSuccess) {
    return (
      <div className="min-h-screen pt-20 pb-12 px-4 bg-secondary/20">
        <div className="container mx-auto max-w-2xl">
          <Card className="border-primary">
            <CardContent className="pt-12 pb-12 text-center">
              <CheckCircle2 className="w-16 h-16 text-primary mx-auto mb-4" />
              <h2 className="text-2xl font-bold text-foreground mb-4">{t("joinUs.successTitle")}</h2>
              <p className="text-muted-foreground mb-4 max-w-md mx-auto">{t("joinUs.successMessage")}</p>
              <div className="flex flex-col sm:flex-row items-center justify-center gap-4 mb-6">
                {contactEmail && (
                  <a href={`mailto:${contactEmail}`} className="flex items-center gap-2 text-primary font-semibold hover:underline">
                    <Mail className="w-5 h-5" /><span>{contactEmail}</span>
                  </a>
                )}
              </div>
              <Button onClick={() => { setIsSuccess(false); setCurrentStep(1); setForm({ storeType: "restaurant", storeTypeCustom: "", accountMode: null, name: "", email: "", phone: "", storeName: "", storeAddress: "", isOwnStore: false, aiGeneratedData: null, autoPublishToCommunity: true }); }}>
                {t("joinUs.submitAnother")}
              </Button>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  return (
    <>
    <div className="min-h-screen pt-4 pb-12 px-4 bg-secondary/20">
      <div className="container mx-auto max-w-2xl">
        <Card>
          <CardHeader className="text-center space-y-2">
            <div className="flex justify-center mb-4">
              <Store className="w-12 h-12 text-primary" />
            </div>
            <CardTitle className="text-3xl font-bold">{t("joinUs.title")}</CardTitle>
            <CardDescription className="text-base">{t("joinUs.description")}</CardDescription>
          </CardHeader>

          {/* Progress */}
          <div className="px-6 pb-4">
            <div className="flex items-center justify-between mb-2">
              <span className="text-sm text-muted-foreground">{t("joinUs.step", { current: currentStep, total: TOTAL_STEPS })}</span>
              <span className="text-sm font-medium">{Math.round(progressPercent)}%</span>
            </div>
            <Progress value={progressPercent} className="h-2" />
            <div className="flex justify-between mt-4">
              {Array.from({ length: TOTAL_STEPS }, (_, i) => i + 1).map((step) => (
                <div key={step} className={cn(
                  "flex items-center justify-center w-8 h-8 rounded-full text-sm font-medium transition-colors",
                  step < currentStep ? "bg-primary text-primary-foreground"
                    : step === currentStep ? "bg-primary text-primary-foreground ring-2 ring-primary ring-offset-2"
                    : "bg-muted text-muted-foreground"
                )}>
                  {step < currentStep ? <Check className="w-4 h-4" /> : step}
                </div>
              ))}
            </div>
          </div>

          <CardContent className="space-y-6">
            {/* Step 1: Store Type */}
            {currentStep === 1 && (
              <div className="space-y-4">
                <div className="text-center mb-4">
                  <h3 className="text-lg font-semibold">{t("joinUs.selectStoreType")}</h3>
                  <p className="text-sm text-muted-foreground">{t("joinUs.selectStoreTypeDesc")}</p>
                </div>
                <div className="grid grid-cols-3 gap-3">
                  {STORE_TYPES.map(({ value, icon: Icon }) => (
                    <div
                      key={value}
                      onClick={() => updateForm({ storeType: value })}
                      className={cn(
                        "relative cursor-pointer rounded-xl border-2 p-4 transition-all hover:border-primary/50 flex flex-col items-center text-center gap-2",
                        form.storeType === value ? "border-primary bg-primary/5" : "border-muted"
                      )}
                    >
                      <div className={cn("p-2 rounded-full", form.storeType === value ? "bg-primary/10" : "bg-muted")}>
                        <Icon className={cn("w-6 h-6", form.storeType === value ? "text-primary" : "text-muted-foreground")} />
                      </div>
                      <span className="text-xs font-medium">{t(`joinUs.storeType.${value}`)}</span>
                      {form.storeType === value && (
                        <div className="absolute top-2 right-2"><Check className="w-4 h-4 text-primary" /></div>
                      )}
                    </div>
                  ))}
                </div>
                {form.storeType === "other" && (
                  <Input
                    placeholder={t("joinUs.storeTypeCustomPlaceholder")}
                    value={form.storeTypeCustom}
                    onChange={(e) => updateForm({ storeTypeCustom: e.target.value })}
                  />
                )}
              </div>
            )}

            {/* Step 2: Account */}
            {currentStep === 2 && (
              <div className="space-y-4">
                <div className="text-center mb-4">
                  <div className="flex justify-center mb-3"><User className="w-8 h-8 text-primary" /></div>
                  <h3 className="text-lg font-semibold">{t("joinUs.accountInfo")}</h3>
                  <p className="text-sm text-muted-foreground">{t("joinUs.accountInfoDesc")}</p>
                </div>

                {user ? (
                  // Logged in: 3 options
                  <div className="space-y-3">
                    {/* Use current account */}
                    <div
                      onClick={() => updateForm({ accountMode: "current" })}
                      className={cn(
                        "cursor-pointer rounded-xl border-2 p-4 transition-all hover:border-primary/50",
                        form.accountMode === "current" ? "border-primary bg-primary/5" : "border-muted"
                      )}
                    >
                      <div className="flex items-center gap-3">
                        <User className="w-5 h-5 text-primary" />
                        <div className="flex-1">
                          <p className="font-medium">{t("joinUs.useCurrentAccount")}</p>
                          <p className="text-xs text-muted-foreground">{user.email}</p>
                        </div>
                        {form.accountMode === "current" && <Check className="w-5 h-5 text-primary" />}
                      </div>
                      {form.accountMode === "current" && (
                        <div className="mt-3 space-y-2 text-sm">
                          <div className="flex justify-between"><span className="text-muted-foreground">{t("joinUs.name")}:</span><span className={!profile?.display_name ? "text-destructive" : ""}>{profile?.display_name || t("joinUs.missing")}</span></div>
                          <div className="flex justify-between"><span className="text-muted-foreground">{t("joinUs.email")}:</span><span>{user.email}</span></div>
                          <div className="flex justify-between"><span className="text-muted-foreground">{t("joinUs.phone")}:</span><span className={!profile?.phone ? "text-destructive" : ""}>{profile?.phone || t("joinUs.missing")}</span></div>
                          {(!profile?.display_name || !profile?.phone) && (
                            <p className="text-xs text-destructive mt-2">{t("joinUs.missingProfileInfo")}</p>
                          )}
                        </div>
                      )}
                    </div>

                    {/* Use another account */}
                    <div
                      onClick={handleSwitchAccount}
                      className="cursor-pointer rounded-xl border-2 border-muted p-4 transition-all hover:border-primary/50"
                    >
                      <div className="flex items-center gap-3">
                        <ChevronRight className="w-5 h-5 text-muted-foreground" />
                        <div className="flex-1">
                          <p className="font-medium">{t("joinUs.useAnotherAccount")}</p>
                          <p className="text-xs text-muted-foreground">{t("joinUs.useAnotherAccountDesc")}</p>
                        </div>
                      </div>
                    </div>

                    {/* Create new account - redirect to /auth */}
                    <div
                      onClick={() => {
                        sessionStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify({ ...form, accountMode: "new" }));
                        navigate("/auth?redirect=/join-us&resumeJoinUs=true&mode=register");
                      }}
                      className="cursor-pointer rounded-xl border-2 border-muted p-4 transition-all hover:border-primary/50"
                    >
                      <div className="flex items-center gap-3">
                        <Mail className="w-5 h-5 text-muted-foreground" />
                        <div className="flex-1">
                          <p className="font-medium">{t("joinUs.createNewAccount")}</p>
                          <p className="text-xs text-muted-foreground">{t("joinUs.createNewAccountDesc")}</p>
                        </div>
                        <ChevronRight className="w-5 h-5 text-muted-foreground" />
                      </div>
                    </div>
                  </div>
                ) : (
                  // Not logged in: 2 options
                  <div className="space-y-3">
                    <div
                      onClick={() => {
                        sessionStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(form));
                        navigate("/auth?redirect=/join-us&resumeJoinUs=true");
                      }}
                      className="cursor-pointer rounded-xl border-2 border-muted p-4 transition-all hover:border-primary/50"
                    >
                      <div className="flex items-center gap-3">
                        <User className="w-5 h-5 text-muted-foreground" />
                        <div className="flex-1">
                          <p className="font-medium">{t("joinUs.haveAccount")}</p>
                          <p className="text-xs text-muted-foreground">{t("joinUs.haveAccountDesc")}</p>
                        </div>
                        <ChevronRight className="w-5 h-5 text-muted-foreground" />
                      </div>
                    </div>

                    <div
                      onClick={() => {
                        sessionStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify({ ...form, accountMode: "new" }));
                        navigate("/auth?redirect=/join-us&resumeJoinUs=true&mode=register");
                      }}
                      className="cursor-pointer rounded-xl border-2 border-muted p-4 transition-all hover:border-primary/50"
                    >
                      <div className="flex items-center gap-3">
                        <Mail className="w-5 h-5 text-muted-foreground" />
                        <div className="flex-1">
                          <p className="font-medium">{t("joinUs.createNewAccount")}</p>
                          <p className="text-xs text-muted-foreground">{t("joinUs.createNewAccountDesc")}</p>
                        </div>
                        <ChevronRight className="w-5 h-5 text-muted-foreground" />
                      </div>
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Step 3: Store Info */}
            {currentStep === 3 && (
              <div className="space-y-4">
                <div className="text-center mb-4">
                  <div className="flex justify-center mb-3"><MapPin className="w-8 h-8 text-primary" /></div>
                  <h3 className="text-lg font-semibold">{t("joinUs.storeInfo")}</h3>
                  <p className="text-sm text-muted-foreground">{t("joinUs.storeInfoDesc")}</p>
                </div>

                <div>
                  <label className="text-sm font-medium">{t("joinUs.restaurantName")} *</label>
                  <Input placeholder={t("joinUs.restaurantNamePlaceholder")} value={form.storeName} onChange={(e) => updateForm({ storeName: e.target.value })} className="mt-1" />
                </div>
                <div>
                  <label className="text-sm font-medium">{t("joinUs.restaurantAddress")} *</label>
                  <Input placeholder={t("joinUs.restaurantAddressPlaceholder")} value={form.storeAddress} onChange={(e) => updateForm({ storeAddress: e.target.value })} className="mt-1" />
                </div>

                <Button type="button" variant="outline" className="w-full" onClick={searchNearbyPlaces} disabled={locatingNearby}>
                  {locatingNearby ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Navigation className="w-4 h-4 mr-2" />}
                  {t("joinUs.useMyLocation")}
                </Button>

                {/* Ownership selection */}
                <div className="space-y-2 pt-2">
                  <label className="text-sm font-medium">{t("joinUs.storeOwnership", "您与该商店的关系")} *</label>
                  <div className="grid grid-cols-2 gap-3">
                    <div
                      onClick={() => updateForm({ isOwnStore: false })}
                      className={cn(
                        "cursor-pointer rounded-xl border-2 p-3 transition-all hover:border-primary/50 text-center",
                        form.isOwnStore === false ? "border-primary bg-primary/5" : "border-muted"
                      )}
                    >
                      <MapPin className={cn("w-5 h-5 mx-auto mb-1", form.isOwnStore === false ? "text-primary" : "text-muted-foreground")} />
                      <p className="text-sm font-medium">{t("joinUs.isRecommender", "我是推荐人")}</p>
                      <p className="text-xs text-muted-foreground mt-0.5">{t("joinUs.isRecommenderDesc", "我想推荐这家商店加入")}</p>
                    </div>
                    <div
                      onClick={() => updateForm({ isOwnStore: true })}
                      className={cn(
                        "cursor-pointer rounded-xl border-2 p-3 transition-all hover:border-primary/50 text-center",
                        form.isOwnStore === true ? "border-primary bg-primary/5" : "border-muted"
                      )}
                    >
                      <Store className={cn("w-5 h-5 mx-auto mb-1", form.isOwnStore === true ? "text-primary" : "text-muted-foreground")} />
                      <p className="text-sm font-medium">{t("joinUs.isOwner", "我是店主")}</p>
                      <p className="text-xs text-muted-foreground mt-0.5">{t("joinUs.isOwnerDesc", "这是我自己经营的商店")}</p>
                    </div>
                </div>
                </div>

                <Dialog open={showNearbyDialog} onOpenChange={setShowNearbyDialog}>
                  <DialogContent className="max-w-md max-h-[80vh]">
                    <DialogHeader>
                      <DialogTitle className="flex items-center gap-2">
                        <MapPin className="w-5 h-5 text-primary" />
                        {t("joinUs.nearbyPlaces")}
                      </DialogTitle>
                    </DialogHeader>
                    <div className="space-y-2 max-h-[60vh] overflow-y-auto pr-1">
                      {nearbyPlaces.map((place, i) => (
                        <div
                          key={i}
                          onClick={() => {
                            updateForm({ storeName: place.name, storeAddress: place.address });
                            setNearbyPlaces([]);
                            setShowNearbyDialog(false);
                          }}
                          className="cursor-pointer rounded-lg border p-3 hover:bg-muted/50 transition-colors"
                        >
                          <div className="flex items-start justify-between gap-2">
                            <div className="min-w-0 flex-1">
                              <p className="font-medium text-sm">{place.name}</p>
                              <p className="text-xs text-muted-foreground mt-0.5 line-clamp-2">{place.address}</p>
                            </div>
                            {place.distance > 0 && (
                              <span className="text-xs text-primary font-medium whitespace-nowrap flex items-center gap-1">
                                <Navigation className="w-3 h-3" />
                                {place.distance < 1000
                                  ? `${Math.round(place.distance)}m`
                                  : `${(place.distance / 1000).toFixed(1)}km`}
                              </span>
                            )}
                          </div>
                        </div>
                      ))}
                      {nearbyPlaces.length === 0 && (
                        <p className="text-center text-sm text-muted-foreground py-8">
                          {t("joinUs.noNearbyPlaces", "未找到附近的店铺")}
                        </p>
                      )}
                    </div>
                  </DialogContent>
                </Dialog>
              </div>
            )}

            {/* Step 4: AI Preview */}
            {currentStep === 4 && (
              <div className="space-y-4">
                <div className="text-center mb-4">
                  <div className="flex justify-center mb-3"><Sparkles className="w-8 h-8 text-primary" /></div>
                  <h3 className="text-lg font-semibold">{t("joinUs.aiPreviewTitle")}</h3>
                  <p className="text-sm text-muted-foreground">{t("joinUs.aiPreviewDesc")}</p>
                </div>

                {isGeneratingPreview ? (
                  <div className="flex flex-col items-center py-12 gap-4">
                    <Loader2 className="w-10 h-10 animate-spin text-primary" />
                    <p className="text-sm text-muted-foreground animate-pulse">{t("joinUs.aiGenerating")}</p>
                  </div>
                ) : form.aiGeneratedData ? (
                  <div className="space-y-4">
                    {/* ── "not_found": AI didn't find any store ── */}
                    {form.aiGeneratedData.verification_status === "not_found" && !form.aiGeneratedData._userConfirmedManual && (
                      <div className="p-4 rounded-lg border border-yellow-500/30 bg-yellow-500/10 space-y-3">
                        <div className="flex items-start gap-3">
                          <AlertTriangle className="w-5 h-5 text-yellow-500 mt-0.5 shrink-0" />
                          <div>
                            <p className="font-medium text-sm">{t("joinUs.storeNotFound", "未找到该商店")}</p>
                            <p className="text-sm text-muted-foreground mt-1">
                              {form.aiGeneratedData.verification_message || t("joinUs.storeNotFoundDesc", "我们在该地址没有找到名为 \"{{name}}\" 的商店。", { name: form.storeName })}
                            </p>
                          </div>
                        </div>
                        <Button
                          type="button"
                          variant="outline"
                          className="w-full gap-2"
                          onClick={() => {
                            updateForm({
                              aiGeneratedData: {
                                ...form.aiGeneratedData,
                                _userConfirmedManual: true,
                                verification_status: "manual",
                              },
                            });
                          }}
                        >
                          <Store className="w-4 h-4" />
                          {t("joinUs.manualFillOption", "商店确实存在，我来手动填写")}
                        </Button>
                      </div>
                    )}

                    {/* ── "different": AI found a different store ── */}
                    {form.aiGeneratedData.verification_status === "different" && !form.aiGeneratedData._userAcceptedDifferent && (
                      <div className="p-4 rounded-lg border border-blue-500/30 bg-blue-500/10 space-y-3">
                        <div className="flex items-start gap-3">
                          <Search className="w-5 h-5 text-blue-500 mt-0.5 shrink-0" />
                          <div>
                            <p className="font-medium text-sm">{t("joinUs.storeFoundDifferent", "找到了不同的商店")}</p>
                            <p className="text-sm text-muted-foreground mt-1">
                              {form.aiGeneratedData.verification_message}
                            </p>
                          </div>
                        </div>

                        {/* Option 1: Accept the found store */}
                        {form.aiGeneratedData.actual_business_name && (
                          <Button
                            type="button"
                            variant="outline"
                            className="w-full justify-start gap-2 h-auto py-3 border-blue-500/30 hover:bg-blue-500/10"
                            onClick={() => {
                              const newType = form.aiGeneratedData.suggested_store_type || form.storeType;
                              updateForm({
                                storeName: form.aiGeneratedData.actual_business_name,
                                storeType: newType,
                                aiGeneratedData: {
                                  ...form.aiGeneratedData,
                                  _userAcceptedDifferent: true,
                                  verification_status: "verified",
                                },
                              });
                              toast({ title: t("joinUs.storeInfoUpdated", "商店信息已更新") });
                            }}
                          >
                            <CheckCircle2 className="w-4 h-4 text-blue-500 shrink-0" />
                            <span className="text-left">
                              <span className="font-medium">{form.aiGeneratedData.actual_business_name}</span>
                              {form.aiGeneratedData.actual_business_type && (
                                <span className="text-muted-foreground"> ({form.aiGeneratedData.actual_business_type})</span>
                              )}
                            </span>
                          </Button>
                        )}

                        {/* Option 2: Store really exists, fill manually */}
                        <Button
                          type="button"
                          variant="ghost"
                          size="sm"
                          className="w-full gap-2 text-muted-foreground"
                          onClick={() => {
                            updateForm({
                              aiGeneratedData: {
                                ...form.aiGeneratedData,
                                _userAcceptedDifferent: true,
                                _userConfirmedManual: true,
                                verification_status: "manual",
                              },
                            });
                          }}
                        >
                          <Store className="w-4 h-4" />
                          {t("joinUs.manualFillOption", "商店确实存在，我来手动填写")}
                        </Button>
                      </div>
                    )}

                    {/* ── Manual fill mode ── */}
                    {form.aiGeneratedData.verification_status === "manual" && (
                      <div className="space-y-3">
                        <div className="flex items-center gap-2 p-3 rounded-lg border border-muted bg-muted/30">
                          <Store className="w-4 h-4 text-primary shrink-0" />
                          <p className="text-sm">{t("joinUs.manualFillHint", "请填写您商店的简介，我们会人工审核。")}</p>
                        </div>
                        <div>
                          <label className="text-sm font-medium">{t("joinUs.editDescription")}</label>
                          <Textarea
                            placeholder={t("joinUs.manualDescriptionPlaceholder", "请描述您的商店...")}
                            value={
                              i18n.language.startsWith("zh")
                                ? form.aiGeneratedData.description_zh || ""
                                : i18n.language.startsWith("pt")
                                ? form.aiGeneratedData.description_pt || ""
                                : form.aiGeneratedData.description_en || ""
                            }
                            onChange={(e) => {
                              const key = i18n.language.startsWith("zh") ? "description_zh" : i18n.language.startsWith("pt") ? "description_pt" : "description_en";
                              updateForm({ aiGeneratedData: { ...form.aiGeneratedData, [key]: e.target.value } });
                            }}
                            rows={3}
                            className="mt-1"
                          />
                        </div>
                      </div>
                    )}

                    {/* ── Verified / Unverified — show normal preview with edit ── */}
                    {(form.aiGeneratedData.verification_status === "verified" || form.aiGeneratedData.verification_status === "unverified") && (
                      <>
                        {form.aiGeneratedData.verification_status === "verified" && (
                          <div className="flex items-center gap-2 p-3 rounded-lg border border-green-500/30 bg-green-500/10">
                            <CheckCircle2 className="w-4 h-4 text-green-500 shrink-0" />
                            <p className="text-sm text-green-700 dark:text-green-400">{t("joinUs.storeVerified", "已验证：该商店信息与网上记录一致")}</p>
                          </div>
                        )}
                        <Card className="overflow-hidden">
                          <div className="relative h-48 bg-muted overflow-hidden group">
                            {form.aiGeneratedData.cover_image_url ? (
                              <>
                                <img src={form.aiGeneratedData.cover_image_url} alt="" className="w-full h-full object-cover" />
                                {/* Re-upload overlay */}
                                <button
                                  type="button"
                                  onClick={() => coverInputRef.current?.click()}
                                  className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-1 cursor-pointer"
                                >
                                  <Camera className="w-6 h-6 text-white" />
                                  <span className="text-xs text-white font-medium">{t("joinUs.changeCover", "更换封面")}</span>
                                </button>
                                {form.aiGeneratedData.cover_image_source === "user_upload" && (
                                  <Badge variant="secondary" className="absolute top-3 left-3 text-[10px] gap-1">
                                    <Upload className="w-3 h-3" />
                                    {t("joinUs.userUploaded", "用户上传")}
                                  </Badge>
                                )}
                              </>
                            ) : (
                              <button
                                type="button"
                                onClick={() => coverInputRef.current?.click()}
                                disabled={isUploadingCover}
                                className="w-full h-full flex flex-col items-center justify-center gap-2 cursor-pointer hover:bg-muted/80 transition-colors"
                              >
                                {isUploadingCover ? (
                                  <Loader2 className="w-8 h-8 text-muted-foreground/50 animate-spin" />
                                ) : (
                                  <>
                                    <Camera className="w-10 h-10 text-muted-foreground/30" />
                                    <span className="text-xs text-muted-foreground">{t("joinUs.uploadCover", "点击上传商店封面照片")}</span>
                                    <span className="text-[10px] text-muted-foreground/60">{t("joinUs.uploadCoverHint", "JPG/PNG/WebP · 最小 400×300 · 最大 5MB")}</span>
                                  </>
                                )}
                              </button>
                            )}
                            <input
                              ref={coverInputRef}
                              type="file"
                              accept="image/jpeg,image/png,image/webp"
                              className="hidden"
                              onChange={handleCoverUpload}
                            />
                            <Button size="icon" variant="secondary" className="absolute top-3 right-3">
                              <Heart className="w-5 h-5" />
                            </Button>
                          </div>
                          <CardHeader className="pb-[15px]">
                            <div className="flex items-start justify-between">
                              <div className="flex flex-col gap-2">
                                <h3 className="font-semibold text-xl text-card-foreground">{form.storeName}</h3>
                                <div className="flex items-center gap-1">
                                  <Navigation className="w-4 h-4 text-primary" />
                                  <span className="font-semibold text-sm text-foreground">0.0 km</span>
                                </div>
                              </div>
                              <div className="flex items-center gap-0.5">
                                <Star className="w-5 h-5 text-muted-foreground" />
                                <span className="text-xs text-muted-foreground text-center whitespace-nowrap">
                                  {t("restaurant.noRatingLine1", "暂无")}<br />{t("restaurant.noRatingLine2", "评分")}
                                </span>
                              </div>
                            </div>
                          </CardHeader>
                          <CardContent className="space-y-2">
                            <div className="flex items-center flex-wrap gap-2">
                              {(() => {
                                const storeTypeLabel = form.storeType === "other" 
                                  ? form.storeTypeCustom 
                                  : t(`joinUs.storeType.${form.storeType}`, form.storeType);
                                return <Badge variant="secondary" className="text-xs">{storeTypeLabel}</Badge>;
                              })()}
                            </div>
                            <div className="flex items-center gap-2 text-muted-foreground text-sm">
                              <MapPin className="w-4 h-4 flex-shrink-0" />
                              <span className="line-clamp-1">{form.storeAddress}</span>
                            </div>
                            {(() => {
                              const desc = i18n.language.startsWith("zh")
                                ? form.aiGeneratedData.description_zh
                                : i18n.language.startsWith("pt")
                                ? form.aiGeneratedData.description_pt
                                : form.aiGeneratedData.description_en;
                              if (!desc) return null;
                              return (
                                <div className="flex items-start gap-2 text-xs text-muted-foreground bg-muted/40 rounded-md px-2.5 py-1.5">
                                  <Store className="w-3.5 h-3.5 text-primary flex-shrink-0 mt-0.5" />
                                  <span className="line-clamp-2 italic leading-relaxed">{desc}</span>
                                </div>
                              );
                            })()}
                            {form.phone && (
                              <div className="flex items-center gap-2 text-muted-foreground text-sm">
                                <Phone className="w-4 h-4 flex-shrink-0" />
                                <span>{form.phone}</span>
                              </div>
                            )}
                          </CardContent>
                          <CardFooter>
                            <Button className="flex-1" onClick={() => {
                              if (form.aiGeneratedData?.draft_restaurant_id) {
                                // Save state before navigating
                                const stateToSave = { ...form, _savedStep: currentStep, _savedDraftStory: draftStory };
                                sessionStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(stateToSave));
                                navigate(`/restaurant/${form.aiGeneratedData.draft_restaurant_id}`);
                              } else {
                                toast({ title: t("joinUs.previewOnly", "这是预览效果，提交后即可查看详情") });
                              }
                            }}>
                              {t("restaurants.viewDetails", "查看详情")}
                            </Button>
                          </CardFooter>
                        </Card>

                        {/* Story snippet visible directly */}
                        {draftStory && (() => {
                          const { buildingNarrative } = getBuildingStoryParts({
                            photo_story_zh: draftStory.zh,
                            photo_story_en: draftStory.en,
                            photo_story_pt: draftStory.pt,
                            address: form.storeAddress,
                          }, i18n.language);
                          if (!buildingNarrative) return null;
                          return (
                            <div className="bg-muted/50 rounded-lg p-4 space-y-2">
                              <div className="flex items-center gap-2 text-sm font-medium text-foreground">
                                <BookOpen className="w-4 h-4 text-primary" />
                                {t("buildingStory", "建筑故事")}
                              </div>
                              <p className="text-sm text-muted-foreground leading-relaxed line-clamp-4 whitespace-pre-line">
                                {buildingNarrative}
                              </p>
                              <Button variant="link" size="sm" className="p-0 h-auto text-primary" onClick={() => {
                                if (form.aiGeneratedData?.draft_restaurant_id) {
                                  const stateToSave = { ...form, _savedStep: currentStep, _savedDraftStory: draftStory };
                                  sessionStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(stateToSave));
                                  navigate(`/restaurant/${form.aiGeneratedData.draft_restaurant_id}`);
                                }
                              }}>
                                {t("readMore", "阅读全文")} →
                              </Button>
                            </div>
                          );
                        })()}

                        <div>
                          <label className="text-sm font-medium">{t("joinUs.editDescription")}</label>
                          <Textarea
                            value={
                              i18n.language.startsWith("zh")
                                ? form.aiGeneratedData.description_zh || ""
                                : i18n.language.startsWith("pt")
                                ? form.aiGeneratedData.description_pt || ""
                                : form.aiGeneratedData.description_en || ""
                            }
                            onChange={(e) => {
                              const key = i18n.language.startsWith("zh") ? "description_zh" : i18n.language.startsWith("pt") ? "description_pt" : "description_en";
                              updateForm({ aiGeneratedData: { ...form.aiGeneratedData, [key]: e.target.value } });
                            }}
                            rows={3}
                            className="mt-1"
                          />
                        </div>
                      </>
                    )}

                    <Button type="button" variant="outline" className="w-full" onClick={generatePreview}>
                      <RefreshCw className="w-4 h-4 mr-2" />
                      {t("joinUs.regenerate")}
                    </Button>
                  </div>
                ) : (
                  <div className="text-center py-8">
                    <p className="text-sm text-muted-foreground mb-4">{t("joinUs.aiPreviewFailed")}</p>
                    <Button type="button" variant="outline" onClick={generatePreview}>
                      <RefreshCw className="w-4 h-4 mr-2" /> {t("joinUs.regenerate")}
                    </Button>
                  </div>
                )}
              </div>
            )}

            {/* Step 5: Review & Submit */}
            {currentStep === 5 && (
              <div className="space-y-4">
                <div className="text-center mb-4">
                  <div className="flex justify-center mb-3"><CheckCircle2 className="w-8 h-8 text-primary" /></div>
                  <h3 className="text-lg font-semibold">{t("joinUs.reviewTitle")}</h3>
                  <p className="text-sm text-muted-foreground">{t("joinUs.reviewDesc")}</p>
                </div>

                <div className="space-y-3 p-4 bg-muted/20 rounded-lg">
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">{t("joinUs.selectStoreType")}:</span>
                    <span className="font-medium">
                      {form.storeType === "other" ? form.storeTypeCustom : t(`joinUs.storeType.${form.storeType}`)}
                    </span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">{t("joinUs.name")}:</span>
                    <span className="font-medium">{form.accountMode === "current" ? profile?.display_name : form.name}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">{t("joinUs.email")}:</span>
                    <span className="font-medium">{form.accountMode === "current" ? user?.email : form.email}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">{t("joinUs.phone")}:</span>
                    <span className="font-medium">{form.accountMode === "current" ? profile?.phone : form.phone}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">{t("joinUs.restaurantName")}:</span>
                    <span className="font-medium">{form.storeName}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">{t("joinUs.restaurantAddress")}:</span>
                    <span className="font-medium truncate max-w-[200px]">{form.storeAddress}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">{t("joinUs.storeOwnership", "商店关系")}:</span>
                    <span className="font-medium">
                      {form.isOwnStore ? t("joinUs.isOwner", "我是店主") : t("joinUs.isRecommender", "我是推荐人")}
                    </span>
                  </div>
                </div>

                {/* Auto publish to community */}
                <label className="flex items-center gap-2 cursor-pointer p-3 rounded-lg bg-muted/20 border border-border/50">
                  <Checkbox
                    checked={form.autoPublishToCommunity}
                    onCheckedChange={(checked) => updateForm({ autoPublishToCommunity: !!checked })}
                  />
                  <span className="text-sm">{t("joinUs.autoPublishToCommunity", "申请成功后自动发布到社区")}</span>
                </label>

                {/* Terms */}
                <div className="text-xs text-muted-foreground text-center">
                  {t("joinUs.consentText")}{" "}
                  <Link to="/privacy-policy" className="text-primary hover:underline">{t("joinUs.privacyPolicy")}</Link>{" "}
                  {t("joinUs.and")}{" "}
                  <Link to="/terms-of-service" className="text-primary hover:underline">{t("joinUs.termsOfService")}</Link>
                </div>
              </div>
            )}

            {/* Navigation */}
            <div className="flex justify-between gap-4 pt-4">
              {currentStep > 1 ? (
                <Button type="button" variant="outline" onClick={handlePrev} className="flex-1">
                  <ChevronLeft className="w-4 h-4 mr-2" /> {t("joinUs.prev")}
                </Button>
              ) : <div className="flex-1" />}

              {currentStep < TOTAL_STEPS ? (
                <Button type="button" onClick={handleNext} className="flex-1">
                  {t("joinUs.next")} <ChevronRight className="w-4 h-4 ml-2" />
                </Button>
              ) : (
                <Button type="button" onClick={onSubmit} className="flex-1" disabled={isSubmitting}>
                  {isSubmitting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                  {t("joinUs.submit")}
                </Button>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>

      <AlertDialog open={showLogoutConfirm} onOpenChange={setShowLogoutConfirm}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t("joinUs.switchAccountTitle", "切换账号")}</AlertDialogTitle>
            <AlertDialogDescription>
              {t("joinUs.switchAccountConfirm", "切换到其他账号需要先退出当前账号，确认继续吗？")}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t("common.cancel", "取消")}</AlertDialogCancel>
            <AlertDialogAction onClick={confirmSwitchAccount}>
              {t("common.confirm", "确认")}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
};

export default JoinUs;
